sql:
SELECT doc_id
FROM spa_documents
WHERE document_status = 'Draft';

SELECT COUNT(doc_id) AS draft_document_count
FROM spa_documents
WHERE document_status = 'Draft';

SELECT document_status, COUNT(doc_id) AS document_count
FROM spa_documents
GROUP BY document_status;

